"""MayaCustomShelf's button icons as base64 encoded strings."""
# pylint: disable=C0103, C0301

import os
import base64
import tempfile


def getIconPath(string):
    """Returns the path for a given icon name."""
    path = os.path.normpath(
        os.path.join(
            tempfile.gettempdir(),
            'MCShelf_{}.png'.format(string)
        )
    )

    if os.path.exists(path):
        return path
    return None


def writeIconsToTempDir(string):
    """Save binary data to file."""
    path = os.path.normpath(
        os.path.join(
            tempfile.gettempdir(),
            'MCShelf_{}.png'.format(string)
        )
    )
    with open(path, 'w') as f:
        f.write(base64.b64decode(icons[string]))


icons = {
    'newCamera32':
    """""",
    'separator16x32':
    """""",
    'toggleFullScreen32':
    """""",
    'viewAll32':
    """""",
    'viewAnim32':
    """""",
    'viewMesh32':
    """""",
    'viewPreset132':
    """""",
    'viewPreset232':
    """""",
    'rsUtility32':
    """""",
    'randomizedDuplicate32':
    """""",
    'resetMesh32':
    """""",
    'viewAll16':
    """""",
    'viewAnim16':
    """""",
    'viewMesh16':
    """""",
}


for k in icons:
    writeIconsToTempDir(k)
